INSERT INTO `reviews` (`id`, `name`, `stars`, `review_text`, `created_at`, `sentiment_score`) VALUES
(1, 'Abhishek Chitre', 4, 'Decent hotel for stay. Rates are also reasonable. Near to Rankala lake.\nRooms snd hotel is well maintained. They do have lift and parking space.\nStaff is polite and helpful. …', '2001-05-04 13:00:00', 0),
(2, 'Anilkumar Kurmi', 5, 'I recently had a wonderful stay at Swamini Hotel in Kolhapur. The location is unbeatable, with the Amba Bai Temple and Rankala Lake, kapiltirth market(for shopping and food) just a short walk away. The hotel staff were incredibly friendly …', '2001-05-04 13:00:00', 0),
(3, 'Arindam Sinha', 4, 'Had a comfortable stay here in the month of November. Location is quite central to almost all the city centre attractions. The staff is very helpful ; they helped us in alloting a washroom after our checkout as my wife was feeling sick. Very much recommended stay😊 …', '2001-05-04 13:00:00', 0),
(4, 'Harshal', 2, 'Excellent stay. Clean n cosy rooms. Clean washrooms..All basics provided. No issues. Stayed in first week January. Mahalaxmi Mandir is just 5 min away. Polite staff. Value for money', '2001-05-04 13:00:00', 0),
(5, 'Nagesh V', 4, 'I had wonderful stay here. Prime location. Very well cooperative staff. Reasonable price & Rooms are awesome..', '2001-05-04 13:00:00', 0),
(6, 'Kaustubh Dange', 4, 'Great Hotel with Convenient Location\nI had a pleasant stay at this hotel. The Mahalakshmi Mandir is within walking distance, making it very convenient for temple visits. However, please note that the parking space is limited and can accommodate up to 4 cars only.', '2001-05-03 13:00:00', 0),
(7, 'Krutika Pednekar', 3, 'Hotel is located next to Rankala Bus stand. Barely 10 mins walking from Mahalakshmi Mandir and Rankala lake. Strategically a good place to stay. Rooms are absolutely clean and hygienic. We stayed here for 3 days. Pertinent to note that this …', '2001-05-04 13:00:00', 0),
(8, 'yash patil', 2, 'Bait-and-Switch Pricing and Uncomfortable Mattress\n\nI recently stayed at  swamini hotel  and was thoroughly disappointed with my …', '2001-04-30 13:00:00', 0),
(9, 'akshay desai', 2, 'Amazing stay, spacious rooms, very nearby to mahalaxmi temple. 24 hrs hot water. Nice and helpful staff. Highly recommended. Must visit', '2001-05-04 13:00:00', 0),
(10, 'VISHWAJIT WASKAR', 4, 'I\'d highly recommend this place to stay if you are planning to visit Kolhapur. Mahalaxmi temple and Rankala Lake are very close by 10 minutes of walking distance. Shahu Palace is 12-20 minutes of distance. Very nit and clean rooms. I appreciate room service and co-operative staff. Nice experience.', '2001-05-04 13:00:00', 0),
(11, 'Vijaykumar Ramamurthy', 1, 'We 6 friends stayed for 1 night. The rooms are spacious and clean.  The staff were very helpful.  It is in an excellent location.  I would strongly recommend this hotel at kolhapur.', '2001-05-04 13:00:00', 0),
(12, 'Della Persis', 2, 'The hotel is at a prime location. Lobby was smelling very pleasant as soon as I entered. The rooms were very tidy and the bathroom was clean too. The staff was very helpful and arranged for transport on request. Overall, a great stay for anyone visiting Kolhapur for darshan.', '2001-05-04 13:00:00', 0),
(13, 'Ravi Amin', 2, 'Rooms are near and clean. Spacious. Service provided is also good and the staff are really courteous. The location is very ideal and near to Rankala stand. From Railway station it\'s 15 minutes. Very ideal.', '2001-05-04 13:00:00', 0),
(14, 'Naveen Kumar', 1, 'Very tidy rooms, max 10min walk to Kolhapur Mahalakshmi temple.. ample 2wheeler / 2wheeler parking space.. thanks to Omkar for guiding us on temple timing, arranging quick breakfast', '2001-05-03 13:00:00', 0),
(15, 'Ashutosh Upadhyay', 4, 'I stayed and halted  for one  night while traveling to goa for mahalaxmi darshan.I opted for classic room which was not enough for 2 Adults and 1 child .I opted for extra mattress and room size is also small.There is no in house restuarant …', '2001-05-01 13:00:00', 0),
(16, 'Rita Shah', 2, 'Excellent room facilities . Clean and very peaceful energy in hotel and room. Very soothing. Must must go in that hotel. Thanks all team members of Swaminathan hotel gor your hospitality', '2001-05-04 13:00:00', 0),
(17, 'Nitin A', 2, 'Place near rankala bus stand and within 1km from Mahalaxmi mandir...clean rooms and good service...restaurant not available but overall good place to stay.', '2001-05-03 13:00:00', 0),
(18, 'Silent Saint', 3, 'Rooms were clean, hot water facility was there for 24hrs. Only issue is parking, though they have 4 slot for 4 wheeler but it was in sloppy position', '2001-05-03 13:00:00', 0),
(19, 'manjunath reddy', 2, 'Hygiene,family friendly with decent amenities like lift and car parking for 2-3 four wheelers.', '2001-05-04 13:00:00', 0),
(20, 'Harshal Dakore', 5, 'The one of the best place to stay in kolhapur... Very convenient for Mahalakshmi Temple and other activities...  The staff and hospitality is just superb, very polite..\nThank you', '2001-05-04 13:00:00', 0),
(21, 'Nitin Kande', 4, 'Nice ambiance, Rooms are very clean and comfortable,all Staff was very polite and supportive.must visit.', '2001-05-04 13:00:00', 0),
(22, 'Sailingthor', 5, 'Best hotel with all locations close by. Very neat and clean. It\'s new hotel ..', '2001-05-04 13:00:00', 0),
(23, 'Teajas Purandarre', 5, 'Excellent Service. Good Cleanliness. Supportive Staff. Overall very good experience.', '2001-05-04 13:00:00', 0),
(24, 'Harshad Sawadkar', 2, 'Had Nice stay. Very close to Ambabai temple. Room was clean and staff is very cooperative', '2001-05-04 13:00:00', 0),
(25, 'Hrithik Saluja', 4, 'Best hotel in kolhapur.  Value for money . Clean rooms and bathrooms. 24 hours hot water.  Very attentive staff. Only problem was they din\'t switch the cable channels on TV even after repeated reminders. Will definitely stay at this hotel …', '2001-05-04 13:00:00', 0),
(26, 'Kailash Chandra', 1, 'Best hotel with all locations close by.very neat and clean and staff was very good and best service for hotel.', '2001-05-04 13:00:00', 0),
(27, 'KEWAL MHATRE', 1, 'Nice and comfortable place to stay.\nIt\'s 5 mins walk from Rankala and 10 mins walk from Mahalakshmi temple.', '2001-05-04 13:00:00', 0),
(28, 'Shekhar Surve', 1, 'Stayed at the hotel on 20th April 2024. Good clean rooms. Good for family stay. Staff was polite and courteous. Total 9 rooms available (3 on each floor). Car parking available (can accommodate only 4 cars). 10-12 minutes walk to Mahalaxmi Ambabai Temple.', '2001-05-04 13:00:00', 0),
(29, 'udaya kirthi', 4, 'Very spacious and well maintained hotel, where rankala lake and mahalaxmi temple are easily accessible. One can have a pleasant and quite stay with family here in Hotel Swamini in Kolhapur at reasonable prices.', '2001-05-04 13:00:00', 0),
(30, 'ishita talukdar', 1, 'I recently stayed at Hotel Swamini, and I was impressed by the spacious rooms featuring attached balconies. The hotel\'s proximity to the temple, just a 7-minute walk away, was perfect for our early morning darshan. However, it\'s worth …', '2001-05-04 13:00:00', 0),
(31, 'prasad tilekar', 2, 'Swamini hotel is very good to stay here rooms are very clean and hygienic. The hotel has a very good ambience with very good hygiene maintained by the management. We requested cake delivery at 11:40 PM and we received the best quality cake …', '2001-05-04 13:00:00', 0),
(32, 'mahavir dugge', 2, 'No complementary breakfast, AC room was small and I feel rates for AC room are too high.', '2001-05-03 13:00:00', 0),
(33, 'sachin raghuvanshi', 3, 'It was a really good experience with this hotel.\nThe rooms are very neat and clean.\nWell maintained and very cooperative staff. …', '2001-05-04 13:00:00', 0),
(34, 'B L', 2, 'The place was neat but the parking arrangement was a makeshift parking.  They make two cars park back to back with no place to maneuver. As a result, in our case they called us in the night (after we had retired for the day) to take out our …', '2001-05-02 13:00:00', 0),
(35, 'Arushi Gupta', 4, 'Amazing place to stay. Near to mahalaxmi temple and rankala lake. Rooms are clean and hygienic with very good ambience. Staff is so supportive and polite. I\'m completely satisfied with their services. Definitely worth for money .', '2001-05-04 13:00:00', 0),
(36, 'Gaurav Kalal', 1, 'Very cooperative staff, nice location, reasonable rate, rooms are also nice.\nThey have limited parking but they manage it nicely. Overall nice experience.', '2001-05-04 13:00:00', 0),
(37, 'Amar Patil', 5, 'Hotel swamini is very good hotel.i will definitely come here again. Because rooms are clean and well maintained. They also provide food service as per our order. Staff is supportive. Worth for money.', '2001-05-04 13:00:00', 0),
(38, 'Capt. A G Unniraj (Raj)', 3, 'Room was clean & tidy. The front desk staff were friendly & helpful. Food could be ordered online. Very close to Mahalaxmi temple just walkable distance.', '2001-05-03 13:00:00', 0),
(39, 'Ajit Kasar', 2, 'It was a great experience with Swamini hotel. The ambiance was so pleasant. The staff is very cooperative and polite too. special thanks to Mr Pratik ..he helped us a lot.. I would like to visit the place again Thank u so much..', '2001-05-04 13:00:00', 0),
(40, 'dhanashri bhoir', 4, 'Near Mahalaxmi temple and rankala lake... Rooms are clean and spacious with all the amenities. They have a lift as well ....parking is also available underground. Overall a good experience 👍 …', '2001-05-04 13:00:00', 0),
(41, 'kripa m.r', 1, 'Very clean and neat. Good rooms', '2001-05-04 13:00:00', 0),
(42, 'Abhishiktha Seelam', 3, 'It\'s a great place to stay in Kolhapur. Rooms are exactly the way displayed in photos during booking. Service & staff cooperation is good.\nHot water , wifi available round the clock. Food is provided as per our requirement. It\'s a safe and secure place to stay.', '2001-05-04 13:00:00', 0),
(43, 'Shefali Davanakar', 5, 'Hotel Swamini is the best option in Kolhapur. It is centrally located and easy access to many places. Service is really good. Would recommend by family and friends.', '2001-05-04 13:00:00', 0),
(44, 'Prathmesh Ingavale', 5, 'Pleasant stay at hotel swamini. Good service provided with well new furnished Rooms. Cleanliness is maintained. Food ordered is best and on time. I will recommend you this hotel for stay in kolhapur.', '2001-05-04 13:00:00', 0),
(45, 'abhishek mandrekar', 3, 'New, clean & premium stay in good price. Good staff & location in the city suitable for families. Less Parking space & no cafe / restaurant in house or nearby is the only compromise.', '2001-05-04 13:00:00', 0),
(46, 'Mangesh Vaidya', 3, 'Good place to stay nearby to Mahalaxmi temple', '2001-05-04 13:00:00', 0),
(47, 'Sarwesh Mohite', 1, 'Rooms are neat n clean. Located at the central of city. Hotel is at walking distance from Mahalxmi temple and rankala location is good. Lots of connectivity options available here. For going to Panhala and jotiba temple, road is passing nearby from this location.', '2001-05-04 13:00:00', 0),
(48, 'thakur hrishikesh', 4, 'Hotel and overall service is amazing. Very neat and clean rooms. Cooperative staff. Loved our stay!!!', '2001-05-04 13:00:00', 0),
(49, 'Shubham Kadam', 4, 'Best hotel in Kolhapur Mahalaxmi temple area  good staff and they keeps hygienic and clean rooms and toilets and rooms are Very spacious and have balcony, hotel has car parking facilities.', '2001-05-04 13:00:00', 0),
(50, 'Aniket Mokal', 4, 'I recently stayed at Swamini Hotel. And it\'s fantastic service which I received from Shahu and Rupesh.\nRooms are neat and clean. …', '2001-05-04 13:00:00', 0),
(51, 'Ankush Gore', 4, 'Easy access to Shri Mahalakshmi mandir, Rankala lake and bus stop.\nRooms we\'ll maintained and clean.\nParking available for 4 wheeler', '2001-05-03 13:00:00', 0),
(52, 'sid shetye', 4, 'This place is very comfortable hygiene\nWill definitely suggest to my family and friends also just few minutes walk to temple overall it was wonderful experience staying here', '2001-05-04 13:00:00', 0),
(53, 'DrDeepali B', 4, 'We had stay here for only 1day,as there was no rooms available near to the temple of mahalaxmi in kolhapur, and it was very nice, clean lodge, with a everything nearby it is available,  rooms are clean and nice ambiance,', '2001-05-04 13:00:00', 0),
(54, 'sankalp powar', 2, 'Delux Rooms are neat n clean and spacious with a balcony. I\'ll recommend this to all if you\'re passing by or visiting mahalaxmi temple.', '2001-05-04 13:00:00', 0),
(55, 'YASHVARDHAN DAVARI', 3, 'Very nice hotel to stay in with cooperative staff and top quality facilities. This hotel gave me a very luxurious and relaxing experience that I couldn\'t find elsewhere in kolhapur. It was a great experience at hotel swamini kolhapur 💯💯. …', '2001-05-04 13:00:00', 0),
(56, 'radhika rane', 1, 'Best stay in Kolhapur.Great Hospitality. Humble n Helpful reception n staff.Will visit again n will recommend to friends and family\nThanks a lot for your help.', '2001-05-04 13:00:00', 0),
(57, 'Sneha Parsekar', 4, 'Nice hotel, location very close to the temple, hotel staff is very polite and cooperative. Thanku', '2001-05-04 13:00:00', 0),
(58, 'Shahid Iqbal', 1, 'Best for accomodation...centre to city', '2001-05-03 13:00:00', 0),
(59, 'shubham shinde', 4, 'Room service was awesome\nStaff was very supportive\nBest hotel to stay', '2001-05-04 13:00:00', 0),
(60, 'aagney inocent', 1, 'It\'s near by mahalaxmi temple and rooms are clean it\'s new hotel service is slow 😔 …', '2001-05-02 13:00:00', 0),
(61, 'Shreya Sawantdesai', 2, 'Good experience at swamini hotel kolhapur, it is near from most of the tourist places. Go for it.', '2001-05-04 13:00:00', 0),
(62, 'Shriram Jawanjal', 4, 'Service are very very Good and Room quality very Good.Thanks Hotel Swamini.', '2001-05-04 13:00:00', 0),
(63, 'Anirudh Singh', 4, 'Very good rooms and service.Value for money', '2001-05-04 13:00:00', 0),
(64, 'harshit kulkarni', 1, 'Good co-operative staff\nGood wifi range\nLift', '2001-05-04 13:00:00', 0),
(65, 'AM ZIKIBARAH', 2, 'Excellent enjoyed', '2001-05-04 13:00:00', 0),
(66, 'darshan sharma', 2, 'Good place to stay with family, 10min walk to temple', '2001-05-03 13:00:00', 0),
(67, 'tushar jagtap', 1, 'This is the place which you must stay whenever you visit Kolhapur. The hotel has a very good ambience with very good hygiene maintained by the management. Special thanks to the staff, the management is so supportive. I can say I have never …', '2001-05-04 13:00:00', 0),
(68, 'CP Ashok', 4, 'It\'s nice place to stay.', '2001-05-04 13:00:00', 0),
(69, 'Deepak Keswad', 1, 'All superb but employees attitude little bit high', '2001-05-03 13:00:00', 0),
(70, 'Tejas Gaikwad', 5, 'I had very best experience here Great job swamini management 👍👍 …', '2001-05-04 13:00:00', 0),
(71, 'ramesh rao', 3, 'It\'s Good peaceful Room... it\'s good', '2001-05-04 13:00:00', 0),
(72, 'Siddhi Patil', 5, 'Best hotel for stay with family', '2001-05-04 13:00:00', 0),
(73, 'Pratham Korade', 4, 'It was vey nice experience of stay at hotel swamini. Rooms are clean and well designed. Friendly staff i ever came across. Strongly recommend to stay at this hotel with your family or friends.', '2001-05-04 13:00:00', 0),
(74, 'sangram jadhav', 4, 'Hotel swamini is one that I will recommend to everybody. Excellent location, great rooms, good service and nice ambience. Good experience at all.', '2001-05-04 13:00:00', 0),
(75, 'P chaitanya sai Sai', 3, 'Good service', '2001-05-03 13:00:00', 0),
(76, 'Anuradha Housnur', 5, 'Comfortable and warm place to stay. Thank you for your prompt hospitality.', '2001-05-04 13:00:00', 0),
(77, 'Pramod Sonawane', 1, 'Best in hotel stay.', '2001-05-04 13:00:00', 0),
(78, 'Suraj Naik', 5, 'Nice service...highly recommended', '2001-05-04 13:00:00', 0),
